&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;​Paragraph formatting options are described as:&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Alignment&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Alignment&amp;nbsp;or&amp;nbsp;justification&lt;strong&gt;&amp;nbsp;refers to the way in which the lines of a paragraph are aligned.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;There are&lt;strong&gt; four types&lt;/strong&gt; of alignment, namely,&lt;strong&gt;&amp;nbsp;left,&amp;nbsp;center,&amp;nbsp;right, and&amp;nbsp;justified.&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Indentation&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The&lt;strong&gt; value in the&amp;nbsp;Before text&amp;nbsp;box &lt;/strong&gt;specifies the width of the &lt;strong&gt;additional empty space that is inserted between the margin and the text on the left-hand side of a paragraph of left-to-right text.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;The&lt;strong&gt; value&amp;nbsp;in the&amp;nbsp;After text&amp;nbsp;box &lt;/strong&gt;specifies the &lt;strong&gt;width of the additional empty space that is inserted between the text and the margin on the right-hand side of a paragraph of left-to-right text.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;A negative value specifies the distance by which the text extends beyond the respective margin.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Spacing&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The&lt;strong&gt; spacing&lt;/strong&gt; between two paragraphs is&lt;strong&gt; determined by the spacing&amp;nbsp;before&amp;nbsp;one paragraph and the spacing&amp;nbsp;after&amp;nbsp;the preceding paragraph, which are displayed and can be modified in the&amp;nbsp;Before&amp;nbsp;and&amp;nbsp;After&amp;nbsp;boxes.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Line spacing&amp;nbsp;refers to the&lt;strong&gt; vertical distance between the lines within a paragraph.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;It determines the location of each line relative to the line above it.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Line and Page Breaks tab (Pagination)&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The paragraph formatting options on the&amp;nbsp;Line and Page Breaks&amp;nbsp;tab under &lt;strong&gt;pagination of the&amp;nbsp;Paragraph&amp;nbsp;dialog box can help you control where automatic page breaks occur in your document.&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;सही उत्तर&amp;nbsp;&lt;span style=&quot;&quot;&gt;&lt;u&gt;&lt;strong&gt;इफेक्ट&lt;/strong&gt;&lt;/u&gt; है।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;MS &lt;span style=&quot;&quot;&gt;वर्ड&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;strong&gt;2016 में &amp;#39;पैराग्राफ&amp;#39; सेटिंग विंडो में उपलब्ध फॉर्मेटिंग विकल्प हैं:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;स्पेसिंग&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;इंडेंटेशन&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;लाइन और पेज ब्रेक विकल्प के तहत पेजिनेशन&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;संरेखण&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;​पैराग्राफ फाॅर्मेटिंग&amp;nbsp;विकल्पों का वर्णन इस प्रकार किया गया है:&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;संरेखण&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;संरेखण या जस्टीफिकेशन&amp;nbsp;&lt;strong&gt;उस तरीके को संदर्भित करता है जिसमें पैराग्राफ की पंक्तियों को संरेखण&amp;nbsp;किया जाता है।&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;संरेखण &lt;strong&gt;चार प्रकार &lt;/strong&gt;के होते हैं, अर्थात्, &lt;strong&gt;बाएँ, मध्य, दाएँ और जस्टिफाइड&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;इंडेंटेशन&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;बिफोर टेक्स्ट बॉक्स में मान&lt;/strong&gt; &lt;strong&gt;अतिरिक्त खाली स्थान की &lt;/strong&gt;चौड़ाई निर्दिष्ट करता है &lt;strong&gt;जो कि मार्जिन और बाएँ-से-दाएँ टेक्स्ट के पैराग्राफ़ के बाएँ पक्ष&amp;nbsp;के टेक्स्ट के बीच डाला जाता है।&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;आफ्टर टेक्स्ट बॉक्स में मान अतिरिक्त खाली स्थान की चौड़ाई &lt;/strong&gt;को निर्दिष्ट करता है &lt;strong&gt;जो टेक्स्ट और मार्जिन के बीच बाएं से दाएं टेक्स्ट के पैराग्राफ के दाईं ओर डाला जाता है।&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;एक नकारात्मक मान उस दूरी को निर्दिष्ट करता है जिसके द्वारा टेक्स्ट संबंधित मार्जिन से आगे बढ़ता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;स्पेसिंग&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;दो पैराग्राफों के बीच की &lt;strong&gt;स्पेसिंग&lt;/strong&gt;&amp;nbsp;एक पैराग्राफ से &lt;strong&gt;पहले और पिछले पैराग्राफ के बाद की स्पेसिंग द्वारा निर्धारित &lt;/strong&gt;की जाती है, जिसे &lt;strong&gt;प्रदर्शित किया जाता है और पहले और बाद के बॉक्स में संशोधित किया जा सकता है।&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;लाइन स्पेसिंग एक &lt;strong&gt;पैराग्राफ के भीतर लाइनों के बीच लंबवत दूरी को संदर्भित करता&lt;/strong&gt; है।&lt;/li&gt;
		&lt;li&gt;यह इसके ऊपर की रेखा के सापेक्ष प्रत्येक रेखा का स्थान निर्धारित करता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;लाइन और पेज ब्रेक्स टैब (पेजिनेशन)&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;पैराग्राफ़ डायलॉग बॉक्स के पेजिनेशन &lt;/strong&gt;के तहत लाइन और पेज ब्रेक्स टैब पर पैराग्राफ फॉर्मेटिंग विकल्प &lt;strong&gt;आपको यह नियंत्रित करने में मदद कर सकते हैं कि आपके डॉक्यूमेंट में स्वचालित पेज ब्रेक कहाँ होते हैं।​&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Ring topology&lt;/strong&gt;.&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Ring network topology&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;The &lt;strong&gt;physical and logical configuration &lt;/strong&gt;of a network&amp;#39;s nodes and links is known as its &lt;strong&gt;network topology&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;Devices like &lt;strong&gt;switches, routers, and software&lt;/strong&gt; with switch and router functionality are typically included in nodes.&lt;/li&gt;
		&lt;li&gt;A &lt;strong&gt;graph&lt;/strong&gt; is a common way to represent network topologies.&lt;/li&gt;
		&lt;li&gt;When two computers are joined to &lt;strong&gt;create a ring&lt;/strong&gt;, the topology is known as a &lt;strong&gt;ring topology&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;The nodes are linked together in a &lt;strong&gt;closed-loop manner&lt;/strong&gt; in the ring network topology. T&lt;/li&gt;
		&lt;li&gt;The message passing is &lt;strong&gt;circular and unidirectional&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Dual Ring Topology &lt;/strong&gt;is another way to make it bidirectional by adding two connections between each Network Node.&lt;/li&gt;
		&lt;li&gt;This topology primarily utilises a &lt;strong&gt;token-based system&lt;/strong&gt;, and each token moves in a single direction in a loop.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;If a token is available in a ring topology, &lt;strong&gt;the node can take it, attach the data, and the destination address, and then leave the token for communication&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The data is taken out by the receiver when this token reaches the destination node, freeing it up to carry the subsequent data.&lt;/li&gt;
	&lt;li&gt;The most common type of ring network is a &lt;strong&gt;metro network&lt;/strong&gt;, which is based on Synchronous Optical Network technology.&lt;/li&gt;
	&lt;li&gt;Network topologies explain how &lt;strong&gt;networks are set up and where traffic flows are located in relation to one another&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The&lt;strong&gt; diagrams &lt;/strong&gt;can be used by administrators t&lt;strong&gt;o decide where each node should be located and the best path for traffic flow&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्&amp;zwj;तर है&amp;nbsp;&lt;u&gt;&lt;strong&gt;रिंग टोपोलॉजी&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;&quot;&gt;&lt;u&gt;&lt;strong&gt;&amp;nbsp;&lt;/strong&gt;&lt;/u&gt;है&lt;/span&gt;।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&amp;nbsp;रिंग नेटवर्क टोपोलॉजी&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;नेटवर्क के नोड्स और लिंक के &lt;strong&gt;भौतिक और तार्किक विन्यास&lt;/strong&gt; को इसके &lt;strong&gt;नेटवर्क टोपोलॉजी&lt;/strong&gt; के रूप में जाना जाता है।&lt;/li&gt;
		&lt;li&gt;स्विच और राउटर कार्यक्षमता वाले&lt;strong&gt; स्विच, राउटर और सॉफ़्टवेयर&lt;/strong&gt; जैसे उपकरण आमतौर पर नोड्स में शामिल होते हैं।&lt;/li&gt;
		&lt;li&gt;नेटवर्क टोपोलॉजीज का प्रतिनिधित्व करने के लिए एक&lt;strong&gt; ग्राफ&lt;/strong&gt; एक सामान्य तरीका है।&lt;/li&gt;
		&lt;li&gt;जब दो कंप्यूटरों को &lt;strong&gt;एक रिंग बनाने&lt;/strong&gt; के लिए जोड़ा जाता है, तो टोपोलॉजी को रिंग टोपोलॉजी के रूप में जाना जाता है।&lt;/li&gt;
		&lt;li&gt;रिंग नेटवर्क टोपोलॉजी में नोड्स को&lt;strong&gt; क्लोज्ड-लूप तरीके&lt;/strong&gt; से एक साथ जोड़ा जाता है। टी&lt;/li&gt;
		&lt;li&gt;पासिंग मैसेज &lt;strong&gt;सर्कुलर और यूनिडायरेक्शनल&lt;/strong&gt; है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;डुअल रिंग टोपोलॉजी&lt;/strong&gt; प्रत्येक नेटवर्क नोड के बीच दो कनेक्शन जोड़कर इसे द्विदिश बनाने का एक और तरीका है।&lt;/li&gt;
		&lt;li&gt;यह टोपोलॉजी मुख्य रूप से एक &lt;strong&gt;टोकन-आधारित प्रणाली &lt;/strong&gt;का उपयोग करती है, और प्रत्येक टोकन एक लूप में एक ही दिशा में चलता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;nbsp;यदि रिंग टोपोलॉजी में टोकन उपलब्ध है, &lt;strong&gt;तो नोड इसे ले सकता है, डेटा और गंतव्य पता संलग्न कर सकता है, और फिर संचार के लिए टोकन छोड़ सकता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;जब यह टोकन गंतव्य नोड तक पहुंचता है, तो डेटा को रिसीवर द्वारा निकाल लिया जाता है, बाद के डेटा को ले जाने के लिए इसे मुक्त कर दिया जाता है।&lt;/li&gt;
	&lt;li&gt;रिंग नेटवर्क का सबसे सामान्य प्रकार एक &lt;strong&gt;मेट्रो नेटवर्क&lt;/strong&gt; है, जो सिंक्रोनस ऑप्टिकल नेटवर्क तकनीक पर आधारित है।&lt;/li&gt;
	&lt;li&gt;नेटवर्क टोपोलॉजी बताती है कि &lt;strong&gt;नेटवर्क कैसे सेट किए जाते हैं और एक दूसरे के संबंध में ट्रैफ़िक प्रवाह कहाँ स्थित होते हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;आरेखों &lt;/strong&gt;का उपयोग प्रशासकों द्वारा यह &lt;strong&gt;तय करने के लिए किया जा सकता है कि प्रत्येक नोड कहाँ स्थित होना चाहिए और ट्रैफ़िक प्रवाह के लिए सर्वोत्तम पथ।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;&quot;&gt;&lt;u&gt;&lt;strong&gt;Internet Assigned Numbers Authority&lt;/strong&gt;&lt;/u&gt;.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Internet Assigned Numbers Authority (IANA)&amp;nbsp;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;The &lt;strong&gt;IANA&lt;/strong&gt; is a standards body that manages &lt;strong&gt;media types, global IP address allocation,&amp;nbsp; root zone management in the Domain Name System (DNS), autonomous system number assignment&lt;/strong&gt;, and other Internet Protocol-related numbers and symbols.&lt;/li&gt;
		&lt;li&gt;It is &lt;strong&gt;currently carried out by&lt;/strong&gt; &lt;strong&gt;ICANN&lt;/strong&gt;, a nonprofit private American business &lt;strong&gt;founded in 1998&lt;/strong&gt; largely for this purpose under a contract with the &lt;strong&gt;United States Department of Commerce&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;From &lt;strong&gt;1998 until 2016&lt;/strong&gt;, IANA was run by ICANN directly before being handed to &lt;strong&gt;Public Technical Identifiers (PTI), an ICANN subsidiary that still manages IANA today&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;Before that, &lt;strong&gt;Jon Postel oversaw IANA primarily at the University of Southern California&amp;#39;s (USC) Information Sciences Institute (ISI)&lt;/strong&gt;, located in Marina Del Rey (Los Angeles), as part of a deal the USC/ISI had with the US Department of Defense.&lt;/li&gt;
		&lt;li&gt;IANA performs its duty in close coordination with the &lt;strong&gt;RFC Editorial team and the Internet Engineering Task Force (IETF)&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Regional Internet Registries (RIRs)&lt;/strong&gt; receive IP address block allocations from IANA.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Addresses are distributed&lt;/strong&gt; by each RIR for a certain region of the globe.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;Number Resource Organization was established by the RIRs&lt;/strong&gt; collectively as a body to represent their shared interests and guarantee that global policy statements are coordinated.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;IANA facilitates the registration of protocols&lt;/strong&gt; and manages protocol registries &lt;strong&gt;in tables of parameters and protocols&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;There were more than&lt;strong&gt; 2,800 registrations and sub registries as of 2015&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;IANA is responsible for maintaining the &lt;strong&gt;IETF RFC5646-defined IANA Language Subtag Registry&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;span style=&quot;&quot;&gt;&lt;u&gt;&lt;strong&gt;इंटरनेट असाइन्ड नंबर्स अथॉरिटी&lt;/strong&gt;&lt;/u&gt; है।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;प्रमुख बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;इंटरनेट असाइन्ड नंबर्स अथॉरिटी (IANA) &lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;आईएएनए&lt;/strong&gt; एक मानक निकाय है जो &lt;strong&gt;मीडिया प्रकार, वैश्विक आईपी पता आवंटन, डोमेन नाम प्रणाली (डीएनएस) में रूट ज़ोन प्रबंधन, स्वायत्त प्रणाली संख्या असाइनमेंट&lt;/strong&gt; और अन्य इंटरनेट प्रोटोकॉल-संबंधित संख्याओं और प्रतीकों का प्रबंधन करता है।&lt;/li&gt;
		&lt;li&gt;वर्तमान में यह कार्य &lt;strong&gt;ICANN&lt;/strong&gt; &lt;strong&gt;द्वारा किया जाता है&lt;/strong&gt; , जो एक गैर-लाभकारी निजी अमेरिकी व्यवसाय &lt;strong&gt;है जिसकी स्थापना 1998 में&lt;/strong&gt; &lt;strong&gt;संयुक्त राज्य अमेरिका के वाणिज्य विभाग&lt;/strong&gt; के साथ एक अनुबंध के तहत मुख्यतः इसी उद्देश्य के लिए की गई थी।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;1998 से 2016 तक&lt;/strong&gt; , IANA को सीधे ICANN द्वारा चलाया जाता था, उसके बाद इसे &lt;strong&gt;पब्लिक टेक्निकल आइडेंटिफायर्स (PTI) को सौंप दिया गया, जो ICANN की एक सहायक कंपनी है जो आज भी IANA का प्रबंधन करती है।&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;इससे पहले, &lt;strong&gt;जॉन पोस्टेल ने यूएससी/आईएसआई के अमेरिकी रक्षा विभाग के साथ हुए एक समझौते के तहत मरीना डेल रे (लॉस एंजिल्स) स्थित दक्षिणी कैलिफोर्निया विश्वविद्यालय (यूएससी) के सूचना विज्ञान संस्थान (आईएसआई) में मुख्य रूप से आईएएनए का निरीक्षण किया था&lt;/strong&gt; ।&lt;/li&gt;
		&lt;li&gt;IANA &lt;strong&gt;, RFC संपादकीय टीम और इंटरनेट इंजीनियरिंग टास्क फोर्स (IETF) के&lt;/strong&gt; साथ निकट समन्वय में अपना कर्तव्य निभाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;क्षेत्रीय इंटरनेट रजिस्ट्री (आरआईआर)&lt;/strong&gt; आईएएनए से आईपी एड्रेस ब्लॉक आवंटन प्राप्त करती हैं।&lt;/li&gt;
	&lt;li&gt;प्रत्येक RIR द्वारा विश्व के एक निश्चित क्षेत्र के लिए &lt;strong&gt;पते वितरित किये जाते हैं&lt;/strong&gt; ।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;नंबर रिसोर्स संगठन की स्थापना आरआईआर द्वारा सामूहिक रूप से एक निकाय के रूप में की गई थी,&lt;/strong&gt; जिसका उद्देश्य उनके साझा हितों का प्रतिनिधित्व करना तथा यह सुनिश्चित करना था कि वैश्विक नीति वक्तव्यों का समन्वय किया जाए।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;IANA प्रोटोकॉल के पंजीकरण की सुविधा प्रदान करता है&lt;/strong&gt; और &lt;strong&gt;मापदंडों और प्रोटोकॉल की तालिकाओं में&lt;/strong&gt; प्रोटोकॉल रजिस्ट्री का प्रबंधन करता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;2015 तक 2,800 से अधिक पंजीकरण और उप-रजिस्ट्रियां&lt;/strong&gt; थीं।&lt;/li&gt;
	&lt;li&gt;IANA &lt;strong&gt;IETF RFC5646-परिभाषित IANA भाषा सबटैग रजिस्ट्री को&lt;/strong&gt; बनाए रखने के लिए जिम्मेदार है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Windows logo key + L.&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;To lock your PC in a Windows 10 operating system Windows logo key + L shortcut is used.&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Press and hold the Windows logo key on your keyboard (this key should appear next to the Alt key), and then press the L key.&lt;/li&gt;
	&lt;li&gt;Your computer will be locked, and the Windows 10 login screen will be displayed.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;Shortcuts in Windows 10&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Windows logo key + D&lt;/strong&gt; is used to &lt;strong&gt;d&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;isplay and hide the desktop.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Ctrl+K &lt;/strong&gt;is a keyboard shortcut that varies depending on the program used.&lt;/li&gt;
	&lt;li&gt;For example, in certain programs, &lt;strong&gt;Ctrl+K is used to insert a hyperlink, and in some browsers, Ctrl+K focuses on the search bar.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Ctrl+L Aligns the line or selected text to the left of the screen.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p style=&quot;&quot;&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;विंडोज लोगो &lt;/strong&gt;&lt;/u&gt;&lt;strong&gt;कुंजी&lt;/strong&gt;&lt;u&gt;&lt;strong&gt; + &lt;span style=&quot;&quot;&gt;L&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;है।&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;अपने कंप्यूटर को विंडोज 10 ऑपरेटिंग सिस्टम में लॉक करने के लिए &amp;quot;विंडोज लोगो &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;कुंजी&lt;/span&gt; + &lt;/strong&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;L&amp;quot;&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;शॉर्टकट का उपयोग किया जाता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;अपने की-बोर्ड पर विंडोज लोगो कुंजी को दबाकर रखिए (यह कीय &lt;span style=&quot;&quot;&gt;Alt&amp;nbsp;&lt;/span&gt;की के बगल में दिखाई देनी चाहिए) और फिर L कुंजी&amp;nbsp;दबाइए।&lt;/li&gt;
	&lt;li&gt;आपका कंप्यूटर लॉक हो जाएगा और विंडोज 10&amp;nbsp;लॉगिन स्क्रीन डिस्प्ले होगी।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;विंडोज 10&amp;nbsp;में शॉर्टकट&lt;/strong&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;विंडोज लोगो &lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;कुंजी&lt;/span&gt;&lt;strong&gt; + &lt;/strong&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;D&lt;/span&gt;&amp;nbsp;का उपयोग&lt;strong&gt; डेस्कटॉप को डिस्प्ले और हाइड करने&amp;nbsp;&lt;/strong&gt;के लिए किया जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;Ctrl+K&lt;/span&gt;&lt;strong&gt;&amp;nbsp;&lt;/strong&gt;एक की-बोर्ड शॉर्टकट है जो &lt;span style=&quot;&quot;&gt;उपयोग&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;nbsp;&lt;/span&gt;किए गए प्रोग्राम के आधार पर बदलता रहता है।&lt;/li&gt;
	&lt;li&gt;उदाहरण के लिए, कुछ प्रोग्रामों में,&lt;strong&gt; हाइपरलिंक डालने के लिए &lt;/strong&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;Ctrl+K&lt;/span&gt;&lt;strong&gt;&amp;nbsp;का उपयोग किया जाता है और कुछ ब्राउज़रों में, &lt;/strong&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;Ctrl+K का उपयोग करने पर कर्सर, सर्च&lt;/span&gt;&lt;strong&gt;&amp;nbsp;बार पर चला जाता&amp;nbsp;है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;​&lt;/strong&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;Ctrl+L&lt;/span&gt;&lt;strong&gt;&amp;nbsp;स्क्रीन के बायीं ओर लाइन या चयनित टेक्स्ट को अलाइन करता है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Enter.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The shortcut key to create a &lt;strong&gt;new paragraph&lt;/strong&gt; in &lt;strong&gt;MS Word &lt;/strong&gt;is the&amp;nbsp;&lt;strong&gt;&amp;lsquo;Enter&amp;rsquo;&lt;/strong&gt; key.&lt;/li&gt;
	&lt;li&gt;This key takes control to a new paragraph in the document.&lt;/li&gt;
	&lt;li&gt;The settings in the paragraph tab like spacing and indentation are followed during the creation of the new paragraph.&lt;/li&gt;
&lt;/ul&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&amp;lsquo;Shift+Enter&amp;rsquo;&lt;/strong&gt; is used to go to a &lt;strong&gt;new line&lt;/strong&gt; in MS Word.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Enter&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;MS-Word&lt;/strong&gt; में एक नया &lt;strong&gt;पैराग्राफ बनाने की शॉर्टकट की (key) &amp;#39;Enter&amp;#39; की&amp;nbsp;&lt;/strong&gt;है।&lt;/li&gt;
	&lt;li&gt;यह की (key) कंट्रोल को डाक्यूमेंट में एक नए पैराग्राफ पर ले जाती है।&lt;/li&gt;
	&lt;li&gt;नए पैराग्राफ के निर्माण के दौरान पैराग्राफ टैब में स्पेसिंग, इंडेंटेशन जैसी सेटिंग्स का अनुसरण किया जाता है।&lt;/li&gt;
	&lt;li&gt;MS-Word में एक नयी &lt;b&gt;पंक्ति&lt;/b&gt;&amp;nbsp;पर जाने के लिए&lt;strong&gt; &amp;#39;Shift+Enter&amp;#39; &lt;/strong&gt;का प्रयोग किया जाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&lt;strong&gt;&amp;nbsp;&lt;u&gt;&lt;span style=&quot;&quot;&gt;Magnetic tape&lt;/span&gt;&lt;/u&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul dir=&quot;ltr&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;strong&gt;Magnetic tape&lt;/strong&gt;&lt;/span&gt;

	&lt;ul&gt;
		&lt;li style=&quot;line-height: 1.38;  margin-top: 0pt; margin-bottom: 0pt;&quot;&gt;&lt;span id=&quot;docs-internal-guid-112c8c2d-7fff-2e78-d38f-0a0ed02dc97a&quot;&gt;&lt;span style=&quot; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;Magnetic tape is a&lt;strong&gt; secondary storage&lt;/strong&gt; device used for storing files of data.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
		&lt;li style=&quot;line-height: 1.38;  margin-top: 0pt; margin-bottom: 0pt;&quot;&gt;&lt;span id=&quot;docs-internal-guid-112c8c2d-7fff-2e78-d38f-0a0ed02dc97a&quot;&gt;&lt;span style=&quot; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;Example: a company&amp;rsquo;s&lt;strong&gt; payroll&lt;/strong&gt; record&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
		&lt;li style=&quot;line-height: 1.38;  margin-top: 0pt; margin-bottom: 0pt;&quot;&gt;&lt;span id=&quot;docs-internal-guid-112c8c2d-7fff-2e78-d38f-0a0ed02dc97a&quot;&gt;&lt;span style=&quot; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;Access is sequential and consists of records that can be accessed one after another as the tape moves along a stationary&lt;strong&gt; read-write&lt;/strong&gt; mechanism.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
		&lt;li style=&quot;line-height: 1.38;  margin-top: 0pt; margin-bottom: 0pt;&quot;&gt;&lt;span id=&quot;docs-internal-guid-112c8c2d-7fff-2e78-d38f-0a0ed02dc97a&quot;&gt;&lt;span style=&quot; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;&lt;strong&gt;Sequential access&lt;/strong&gt; is a term describing a group of elements (such as data in a memory array or a disk file or on magnetic tape data storage) being accessed in a predetermined, ordered sequence.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;div bis_skin_checked=&quot;1&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&amp;nbsp;SSD&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;A solid-state drive (SSD) is a new generation of &lt;strong&gt;storage devices&lt;/strong&gt; used in computers.&lt;/li&gt;
		&lt;li&gt;SSDs use &lt;strong&gt;flash-based memory&lt;/strong&gt;, which is much faster than a traditional mechanical hard disk.&lt;/li&gt;
		&lt;li&gt;Upgrading to an SSD is one of the best ways to&lt;strong&gt; speed up&lt;/strong&gt; your computer.&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;div bis_skin_checked=&quot;1&quot;&gt;
&lt;div bis_skin_checked=&quot;1&quot;&gt;
&lt;ul&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&gt;Hard disk&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;A hard disk is an electromechanical data &lt;strong&gt;storage device&lt;/strong&gt; from which data is accessed in a&lt;strong&gt; random-access&lt;/strong&gt; manner, individual blocks of data can be stored or retrieved in any order&lt;/li&gt;
		&lt;li&gt;Both &lt;strong&gt;sequential&lt;/strong&gt; and&lt;strong&gt; random&lt;/strong&gt; access of data is possible in a hard disk&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;DRAM&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;Inside a dynamic RAM chip, each memory cell holds one bit of information and is made up of two parts: a transistor and a capacitor.&lt;/li&gt;
		&lt;li&gt;As DRAM has a capacitor, it continuously leaks current.&lt;/li&gt;
		&lt;li&gt;Therefore it requires frequent refresh which consumes power.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;<br><br>&lt;p&gt;सही उत्&amp;zwj;तर&amp;nbsp;&lt;span style=&quot;&quot;&gt;&lt;u&gt;&lt;strong&gt;मैग्नेटिक&amp;nbsp;&lt;/strong&gt;&lt;/u&gt;&lt;u&gt;&lt;strong&gt;टेप&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;है&lt;/span&gt;।&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul dir=&quot;ltr&quot;&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;मैग्नेटिक&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;टेप&lt;/span&gt;&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li style=&quot;line-height: 1.38;  margin-top: 0pt; margin-bottom: 0pt;&quot;&gt;मैग्नेटिक टेप एक &lt;strong&gt;द्वितीयक&lt;/strong&gt;&lt;strong&gt; स्टोरेज&lt;/strong&gt; डिवाइस है जिसका इस्तेमाल डेटा की फाइलों को स्टोर करने के लिए किया जाता है।&lt;/li&gt;
		&lt;li style=&quot;line-height: 1.38;  margin-top: 0pt; margin-bottom: 0pt;&quot;&gt;उदाहरण: एक कंपनी का &lt;strong&gt;पेरोल &lt;/strong&gt;रिकॉर्ड&lt;/li&gt;
		&lt;li style=&quot;line-height: 1.38;  margin-top: 0pt; margin-bottom: 0pt;&quot;&gt;एक्सेस सेक्वेंसिअल&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);   &quot;&gt;होती&amp;nbsp;&lt;/span&gt;है और इसमें ऐसे रिकॉर्ड होते हैं जिन्हें एक के बाद एक एक्सेस किया जा सकता है क्योंकि टेप एक स्थिर &lt;strong&gt;रीड-राइट&lt;/strong&gt; मैकेनिज्म के साथ चलता है।&lt;/li&gt;
		&lt;li style=&quot;line-height: 1.38;  margin-top: 0pt; margin-bottom: 0pt;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;सेक्वेंशिअल&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;एक्सेस&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;एक शब्द है जो तत्वों के समूह (जैसे कि मेमोरी ऐरे या डिस्क फ़ाइल या &lt;span style=&quot;&quot;&gt;मैग्नेटिक&amp;nbsp;&lt;/span&gt;टेप&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;में डेटा&lt;/span&gt; स्टोरेज) का वर्णन करता है, जिसे पूर्व निर्धारित&amp;nbsp;क्रम&amp;nbsp;में एक्सेस किया जा रहा है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;SSD&lt;/span&gt;&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;सॉलिड-स्टेट ड्राइव (SSD) कंप्यूटर में उपयोग किए जाने वाले &lt;strong&gt;स्टोरेज डिवाइस&lt;/strong&gt; की एक नई पीढ़ी है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;SSDs&lt;/span&gt; &lt;strong&gt;फ्लैश-आधारित मेमोरी&lt;/strong&gt; का उपयोग करते हैं, जो पारंपरिक यांत्रिक हार्ड डिस्क की तुलना में बहुत तेज है।&lt;/li&gt;
		&lt;li&gt;SSD में अपग्रेड करना आपके कंप्यूटर को&lt;strong&gt; गति देने&lt;/strong&gt; के सर्वोत्तम तरीकों में से एक है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;
&lt;div&gt;
&lt;ul&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&gt;हार्ड डिस्क&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;हार्ड डिस्क एक इलेक्ट्रोमैकेनिकल डेटा &lt;strong&gt;स्टोरेज डिवाइस&lt;/strong&gt; है जिससे डेटा को&lt;strong&gt; रैंडम-एक्सेस&lt;/strong&gt; तरीके से एक्सेस किया जाता है, डेटा के अलग-अलग ब्लॉक को किसी भी क्रम में स्टोर या पुनर्प्राप्त किया जा सकता है&lt;/li&gt;
		&lt;li&gt;हार्ड डिस्क में डेटा की &lt;strong&gt;क्रमिक (&lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;सेक्वेंशिअल&lt;/span&gt;)&amp;nbsp;और &lt;strong&gt;रैंडम &lt;/strong&gt;एक्सेस दोनों संभव है&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;DRAM&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;एक डायनेमिक रैम चिप के अंदर, प्रत्येक मेमोरी सेल में एक बिट जानकारी होती है और यह दो भागों से बना होता है: एक ट्रांजिस्टर और एक कैपेसिटर।&lt;/li&gt;
		&lt;li&gt;चूंकि DRAM&amp;nbsp;में &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;कैपेसिटर&lt;/span&gt; होता है, यह लगातार करंट की आपूर्ति करता है।&lt;/li&gt;
		&lt;li&gt;इसलिए इसे बार-बार रिफ्रेश करने की आवश्यकता होती है जिससे बिजली की खपत होती&amp;nbsp;है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
